@@ -12,6 +12,15 @@ import (
 	"time"
 )

+// drainAndClose fully drains and closes an HTTP response body.
+// Draining before close allows the underlying TCP connection to be reused.
+func drainAndClose(body io.ReadCloser) {
+	if body != nil {
+		io.Copy(io.Discard, body)
+		body.Close()
+	}
+}
